// ============================================
// Wallet Manager
// ============================================

class WalletManager {
  constructor() {
    this.wallets = new Map();
    this.providers = new Map();
  }

  getProvider(network = CONFIG.defaultNetwork) {
    if (!this.providers.has(network)) {
      const rpcUrl = CONFIG.networks[network];
      if (!rpcUrl) {
        throw new Error(`Unknown network: ${network}`);
      }
      const provider = new ethers.JsonRpcProvider(rpcUrl);
      this.providers.set(network, provider);
    }
    return this.providers.get(network);
  }

  addWallet(name, privateKey, network = CONFIG.defaultNetwork) {
    if (!privateKey) {
      throw new Error(`Private key is required for wallet: ${name}`);
    }
    // Validate private key format
    if (!privateKey.startsWith('0x')) {
      privateKey = '0x' + privateKey;
    }
    const provider = this.getProvider(network);
    const wallet = new ethers.Wallet(privateKey, provider);
    this.wallets.set(name, { wallet, network });
    console.log(`Wallet "${name}" added: ${wallet.address} on ${network}`);
    return wallet.address;
  }

  getWallet(name) {
    const entry = this.wallets.get(name);
    if (!entry) {
      throw new Error(`Wallet not found: ${name}`);
    }
    return entry.wallet;
  }

  getWalletAddress(name) {
    return this.getWallet(name).address;
  }

  listWallets() {
    const list = [];
    for (const [name, { wallet, network }] of this.wallets.entries()) {
      list.push({ name, address: wallet.address, network });
    }
    return list;
  }
}

// ============================================
// Transaction Service
// ============================================

class TransactionService {
  constructor(walletManager) {
    this.walletManager = walletManager;
    this.transactionHistory = [];
  }

  async getBalance(walletName) {
    const wallet = this.walletManager.getWallet(walletName);
    const balance = await wallet.provider.getBalance(wallet.address);
    return {
      wei: balance.toString(),
      ether: ethers.formatEther(balance),
    };
  }

  async getBalanceOfAddress(address, network = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(network);
    const balance = await provider.getBalance(address);
    return {
      wei: balance.toString(),
      ether: ethers.formatEther(balance),
    };
  }

  async estimateGas(walletName, to, value, data = '0x') {
    const wallet = this.walletManager.getWallet(walletName);
    const tx = {
      to,
      value: ethers.parseEther(value.toString()),
      data,
    };
    const gasEstimate = await wallet.provider.estimateGas({
      ...tx,
      from: wallet.address,
    });
    const feeData = await wallet.provider.getFeeData();
    return {
      gasLimit: gasEstimate.toString(),
      gasPrice: feeData.gasPrice ? feeData.gasPrice.toString() : null,
      maxFeePerGas: feeData.maxFeePerGas ? feeData.maxFeePerGas.toString() : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? feeData.maxPriorityFeePerGas.toString() : null,
      estimatedCostWei: (gasEstimate * (feeData.gasPrice || feeData.maxFeePerGas)).toString(),
      estimatedCostEther: ethers.formatEther(gasEstimate * (feeData.gasPrice || feeData.maxFeePerGas)),
    };
  }

  async sendETH(walletName, toAddress, amountInEther, options = {}) {
    const wallet = this.walletManager.getWallet(walletName);

    console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}...`);

    // Build transaction
    const tx = {
      to: toAddress,
      value: ethers.parseEther(amountInEther.toString()),
    };

    // Optional gas settings
    if (options.gasLimit) {
      tx.gasLimit = options.gasLimit;
    }
    if (options.maxFeePerGas) {
      tx.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
    }
    if (options.maxPriorityFeePerGas) {
      tx.maxPriorityFeePerGas = ethers.parseUnits(options.maxPriorityFeePerGas.toString(), 'gwei');
    }
    if (options.nonce !== undefined) {
      tx.nonce = options.nonce;
    }

    // Send with retry logic
    const result = await this._sendWithRetry(wallet, tx);

    // Store in history
    this.transactionHistory.push({
      type: 'ETH_TRANSFER',
      from: wallet.address,
      to: toAddress,
      amount: amountInEther,
      hash: result.hash,
      timestamp: new Date().toISOString(),
    });

    return result;
  }

  async _sendWithRetry(wallet, tx, retries = CONFIG.maxRetries) {
    for (let attempt = 1; attempt <= retries; attempt++) {
      try {
        const txResponse = await wallet.sendTransaction(tx);
        console.log(`Transaction sent: ${txResponse.hash} (attempt ${attempt})`);

        // Wait for confirmation
        const receipt = await txResponse.wait(1);
        console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

        return {
          hash: txResponse.hash,
          blockNumber: receipt.blockNumber,
          gasUsed: receipt.gasUsed.toString(),
          effectiveGasPrice: receipt.gasPrice ? receipt.gasPrice.toString() : null,
          status: receipt.status === 1 ? 'success' : 'failed',
          receipt,
        };
      } catch (error) {
        console.error(`Attempt ${attempt} failed: ${error.message}`);
        if (attempt === retries) {
          throw new Error(`Transaction failed after ${retries} attempts: ${error.message}`);
        }
        // Wait before retrying
        await new Promise((resolve) => setTimeout(resolve, CONFIG.retryDelayMs * attempt));
      }
    }
  }

  getTransactionHistory() {
    return this.transactionHistory;
  }
}

