class SmartContractService {
  constructor(walletManager) {
    this.walletManager = walletManager;
    this.contracts = new Map();
  }

  loadContract(name, address, abi, walletName = null) {
    let signerOrProvider;
    if (walletName) {
      signerOrProvider = this.walletManager.getWallet(walletName);
    } else {
      signerOrProvider = this.walletManager.getProvider();
    }

    const contract = new ethers.Contract(address, abi, signerOrProvider);
    this.contracts.set(name, { contract, address, abi });
    console.log(`Contract "${name}" loaded at ${address}`);
    return contract;
  }

  getContract(name) {
    const entry = this.contracts.get(name);
    if (!entry) {
      throw new Error(`Contract not found: ${name}`);
    }
    return entry.contract;
  }

  connectContractToWallet(contractName, walletName) {
    const entry = this.contracts.get(contractName);
    if (!entry) {
      throw new Error(`Contract not found: ${contractName}`);
    }
    const wallet = this.walletManager.getWallet(walletName);
    return entry.contract.connect(wallet);
  }

  async callReadFunction(contractName, functionName, ...args) {
    const contract = this.getContract(contractName);
    console.log(`Calling ${contractName}.${functionName}(${args.join(', ')})...`);
    const result = await contract[functionName](...args);
    return result;
  }

  async callWriteFunction(contractName, walletName, functionName, args = [], options = {}) {
    const entry = this.contracts.get(contractName);
    if (!entry) {
      throw new Error(`Contract not found: ${contractName}`);
    }

    const wallet = this.walletManager.getWallet(walletName);
    const connectedContract = entry.contract.connect(wallet);

    console.log(`Executing ${contractName}.${functionName}(${args.join(', ')}) from ${wallet.address}...`);

    // Build overrides
    const overrides = {};
    if (options.value) {
      overrides.value = ethers.parseEther(options.value.toString());
    }
    if (options.gasLimit) {
      overrides.gasLimit = options.gasLimit;
    }

    const tx = await connectedContract[functionName](...args, overrides);
    console.log(`Transaction sent: ${tx.hash}`);

    const receipt = await tx.wait(1);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    return {
      hash: tx.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
      events: receipt.logs,
      receipt,
    };
  }

  async deployContract(walletName, abi, bytecode, constructorArgs = [], options = {}) {
    const wallet = this.walletManager.getWallet(walletName);
    console.log(`Deploying contract from ${wallet.address}...`);

    const factory = new ethers.ContractFactory(abi, bytecode, wallet);

    const overrides = {};
    if (options.gasLimit) {
      overrides.gasLimit = options.gasLimit;
    }
    if (options.value) {
      overrides.value = ethers.parseEther(options.value.toString());
    }

    const contract = await factory.deploy(...constructorArgs, overrides);
    console.log(`Deployment transaction: ${contract.deploymentTransaction().hash}`);

    await contract.waitForDeployment();
    const address = await contract.getAddress();
    console.log(`Contract deployed at: ${address}`);

    return {
      address,
      hash: contract.deploymentTransaction().hash,
      contract,
    };
  }

  listenToEvent(contractName, eventName, callback) {
    const contract = this.getContract(contractName);
    contract.on(eventName, (...args) => {
      const event = args[args.length - 1]; // Last argument is the event object
      console.log(`Event "${eventName}" detected in tx: ${event.log.transactionHash}`);
      callback(...args);
    });
    console.log(`Listening for "${eventName}" events on ${contractName}`);
  }

  removeAllListeners(contractName, eventName = null) {
    const contract = this.getContract(contractName);
    if (eventName) {
      contract.removeAllListeners(eventName);
    } else {
      contract.removeAllListeners();
    }
  }
}

