const ERC20_ABI = [
  'function name() view returns (string)',
  'function symbol() view returns (string)',
  'function decimals() view returns (uint8)',
  'function totalSupply() view returns (uint256)',
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function transferFrom(address from, address to, uint256 amount) returns (bool)',
  'event Transfer(address indexed from, address indexed to, uint256 value)',
  'event Approval(address indexed owner, address indexed spender, uint256 value)',
];

class ERC20Service {
  constructor(walletManager) {
    this.walletManager = walletManager;
  }

  getTokenContract(tokenAddress, walletName = null) {
    let signerOrProvider;
    if (walletName) {
      signerOrProvider = this.walletManager.getWallet(walletName);
    } else {
      signerOrProvider = this.walletManager.getProvider();
    }
    return new ethers.Contract(tokenAddress, ERC20_ABI, signerOrProvider);
  }

  async getTokenInfo(tokenAddress) {
    const contract = this.getTokenContract(tokenAddress);
    const [name, symbol, decimals, totalSupply] = await Promise.all([
      contract.name(),
      contract.symbol(),
      contract.decimals(),
      contract.totalSupply(),
    ]);
    return {
      address: tokenAddress,
      name,
      symbol,
      decimals: Number(decimals),
      totalSupply: ethers.formatUnits(totalSupply, decimals),
    };
  }

  async getTokenBalance(tokenAddress, ownerAddress) {
    const contract = this.getTokenContract(tokenAddress);
    const decimals = await contract.decimals();
    const balance = await contract.balanceOf(ownerAddress);
    return {
      raw: balance.toString(),
      formatted: ethers.formatUnits(balance, decimals),
    };
  }

  async transferToken(tokenAddress, walletName, toAddress, amount) {
    const wallet = this.walletManager.getWallet(walletName);
    const contract = this.getTokenContract(tokenAddress, walletName);
    const decimals = await contract.decimals();
    const parsedAmount = ethers.parseUnits(amount.toString(), decimals);

    console.log(`Transferring ${amount} tokens to ${toAddress}...`);
    const tx = await contract.transfer(toAddress, parsedAmount);
    const receipt = await tx.wait(1);

    return {
      hash: tx.hash,
      blockNumber: receipt.blockNumber,
      from: wallet.address,
      to: toAddress,
      amount,
      status: receipt.status === 1 ? 'success' : 'failed',
    };
  }

  async approveSpender(tokenAddress, walletName, spenderAddress, amount) {
    const contract = this.getTokenContract(tokenAddress, walletName);
    const decimals = await contract.decimals();
    const parsedAmount = ethers.parseUnits(amount.toString(), decimals);

    console.log(`Approving ${spenderAddress} to spend ${amount} tokens...`);
    const tx = await contract.approve(spenderAddress, parsedAmount);
    const receipt = await tx.wait(1);

    return {
      hash: tx.hash,
      blockNumber: receipt.blockNumber,
      status: receipt.status === 1 ? 'success' : 'failed',
    };
  }

  async getAllowance(tokenAddress, ownerAddress, spenderAddress) {
    const contract = this.getTokenContract(tokenAddress);
    const decimals = await contract.decimals();
    const allowance = await contract.allowance(ownerAddress, spenderAddress);
    return {
      raw: allowance.toString(),
      formatted: ethers.formatUnits(allowance, decimals),
    };
  }
}

// ============================================
// Blockchain Monitor Service
// ============================================

class BlockchainMonitor {
  constructor(walletManager) {
    this.walletManager = walletManager;
    this.watchedAddresses = new Map();
  }

  async getCurrentBlock(network = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(network);
    return await provider.getBlockNumber();
  }

  async getBlock(blockNumber, network = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(network);
    return await provider.getBlock(blockNumber);
  }

  async getTransaction(txHash, network = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(network);
    const tx = await provider.getTransaction(txHash);
    const receipt = await provider.getTransactionReceipt(txHash);
    return { transaction: tx, receipt };
  }

  async getGasPrice(network = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(network);
    const feeData = await provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : null,
      maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei' : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
        ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei'
        : null,
    };
  }

  watchAddress(address, callback, network = CONFIG.defaultNetwork) {
    const provider = this.walletManager.getProvider(network);
    const filter = {
      address: null,
      topics: [],
    };

    // Watch for new blocks and check for transactions involving the address
    const listener = async (blockNumber) => {
      try {
        const block = await provider.getBlock(blockNumber, true);
        if (block && block.transactions) {
          for (const txHash of block.transactions) {
            const tx = await provider.getTransaction(txHash);
            if (tx && (tx.from?.toLowerCase() === address.toLowerCase() || tx.to?.toLowerCase() === address.toLowerCase())) {
              callback({
                blockNumber,
                hash: tx.hash,
                from: tx.from,
                to: tx.to,
                value: ethers.formatEther(tx.value),
                type: tx.from?.toLowerCase() === address.toLowerCase() ? 'outgoing' : 'incoming',
              });
            }
          }
        }
      } catch (error) {
        console.error(`Error watching address: ${error.message}`);
      }
    };

    provider.on('block', listener);
    this.watchedAddresses.set(address, { listener, provider });
    console.log(`Watching address: ${address}`);
  }

  stopWatching(address) {
    const entry = this.watchedAddresses.get(address);
    if (entry) {
      entry.provider.removeListener('block', entry.listener);
      this.watchedAddresses.delete(address);
      console.log(`Stopped watching address: ${address}`);
    }
  }

  stopAllWatching() {
    for (const [address] of this.watchedAddresses) {
      this.stopWatching(address);
    }
  }
}

