// Batch Transaction Service
// ============================================

class BatchTransactionService {
  constructor(walletManager) {
    this.walletManager = walletManager;
  }

  async sendBatchETH(walletName, recipients) {
    // recipients: [{ address, amount }]
    const wallet = this.walletManager.getWallet(walletName);
    let nonce = await wallet.provider.getTransactionCount(wallet.address);
    const results = [];

    console.log(`Sending batch of ${recipients.length} ETH transactions...`);

    for (const recipient of recipients) {
      try {
        const tx = await wallet.sendTransaction({
          to: recipient.address,
          value: ethers.parseEther(recipient.amount.toString()),
          nonce: nonce++,
        });

        results.push({
          to: recipient.address,
          amount: recipient.amount,
          hash: tx.hash,
          status: 'pending',
        });

        console.log(`Sent ${recipient.amount} ETH to ${recipient.address}: ${tx.hash}`);
      } catch (error) {
        results.push({
          to: recipient.address,
          amount: recipient.amount,
          error: error.message,
          status: 'failed',
        });
        console.error(`Failed to send to ${recipient.address}: ${error.message}`);
      }
    }

    // Wait for all pending transactions
    for (const result of results) {
      if (result.status === 'pending') {
        try {
          const receipt = await wallet.provider.waitForTransaction(result.hash, 1);
          result.status = receipt.status === 1 ? 'success' : 'reverted';
          result.blockNumber = receipt.blockNumber;
        } catch (error) {
          result.status = 'failed';
          result.error = error.message;
        }
      }
    }

    return results;
  }
}

